class Solution:
    def findAllConcatenatedWordsInADict(self, words):
        word_set = set(words)
        def can_form(w):
            if not w:
                return False
            n = len(w)
            dp = [0] * (n + 1)
            dp[0] = 1
            for j in range(1, n + 1):
                for i in range(j):
                    if dp[i] and w[i:j] in word_set and w[i:j] != w:
                        dp[j] = dp[i] + 1
            return dp[n] >= 2
        return [w for w in words if can_form(w)]

