class Solution:
    def findAllConcatenatedWordsInADict(self, words):
        word_set = set(words)
        res = []
        for w in words:
            if not w:
                continue
            n = len(w)
            dp = [False] * (n + 1)
            dp[0] = True
            parts = [0] * (n + 1)
            for j in range(1, n + 1):
                for i in range(j):
                    seg = w[i:j]
                    if dp[i] and seg in word_set and seg != w:
                        dp[j] = True
                        parts[j] = parts[i] + 1
            if dp[n] and parts[n] >= 2:
                res.append(w)
        return res

