var findAllConcatenatedWordsInADict = function(words) {
    const wordSet = new Set(words);
    const res = [];
    for (const w of words) {
        if (!w) continue;
        const n = w.length;
        const dp = new Array(n + 1).fill(false);
        const parts = new Array(n + 1).fill(0);
        dp[0] = true;
        for (let j = 1; j <= n; j++) {
            for (let i = 0; i < j; i++) {
                const seg = w.slice(i, j);
                if (dp[i] && wordSet.has(seg) && seg !== w) {
                    dp[j] = true;
                    parts[j] = parts[i] + 1;
                }
            }
        }
        if (dp[n] && parts[n] >= 2) res.push(w);
    }
    return res;
};
